use std::collections::VecDeque;

struct DataProcessor { 
    queue: VecDeque<i32>,
}

impl DataProcessor {
    fn new(data: Vec<i32>) -> Self {
        let mut queue = VecDeque::new();
        for item in data {
            queue.push_back(item);
        }
        DataProcessor { queue }
    }

    fn process_all(&self) -> i32 {
        let mut total = 0;
        let mut count = 0;
        for &value in self.queue.iter() {
            total += value * 2;
            count += 1;
        }
        total / count
    }
}

fn main() {
    let data_set = vec![10, 20, 30, 40, 50];
    let processor = DataProcessor::new(data_set);
    let result = processor.process_all();
    println!("The calculated average is: {}", result);
}

