struct ItemProcessor<'a> {
    source: &'a [i32],
}

impl<'a> Iterator for ItemProcessor<'a> {
    type Item = i32;

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(value) = self.source.iter().find(|&&x| x % 3 == 0) {
            Some(*value)
        } else {
            None
        }
    }
}

fn main() {
    let data = vec![1, 2, 3, 4, 5, 6, 7];
    let mut processor = ItemProcessor { source: &data };

    println!("Processing items...");
    while let Some(item) = processor.next() {
        println!("Found item: {}", item);
    }
}

use std::collections::HashMap;

struct WordCounter {
    counts: HashMap<String, i32>,
}

impl WordCounter {
    fn new() -> Self {
        WordCounter { 
            counts: HashMap::new()
        }
    }

    fn process_word(&mut self, word: &str) {
        let entry = self.counts.entry(word.to_string()).or_insert(0);
        *entry += 1;
    }
}

impl Iterator for WordCounter {
    type Item = (String, i32);

    fn next(&mut self) -> Option<Self::Item> {
        if self.counts.is_empty() {
            return None;
        }

        let mut item: Option<(String, i32)> = None;
        let mut keys_to_remove = Vec::new();

        for (word, count) in self.counts.iter_mut() {
            if item.is_none() {
                item = Some((word.clone(), *count));
            }
            keys_to_remove.push(word.clone());
        }

        self.counts.clear();
        item
    }
}

fn main() {
    let mut counter = WordCounter::new();
    counter.process_word("hello");
    counter.process_word("world");
    counter.process_word("hello");
    counter.process_word("rust");
    counter.process_word("world");

    let mut iterator = counter;
    while let Some((word, count)) = iterator.next() {
        println!("{}: {}", word, count);
    }
}

use std::fmt;

struct DataPacket {
    data: Vec<i32>,
    index: usize,
}

impl Iterator for DataPacket {
    type Item = i32;

    fn next(&mut self) -> Option<Self::Item> {
        if self.index < self.data.len() {
            let item = self.data[self.index];
            self.index += 1;
            Some(item)
        } else {
            None
        }
    }
}

fn main() {
    let packets = DataPacket {
        data: vec![10, 20, 30, 40],
        index: 0,
    };

    let sum: i32 = packets.collect::<Vec<i32>>().iter().sum();
    println!("The total sum is: {}", sum);
}

use std::fmt;

struct MyContainer<T> {
    items: Vec<T>
}

impl<T: Clone + fmt::Debug> Iterator for MyContainer<T> {
    type Item = T;

    fn next(&mut self) -> Option<Self::Item> {
        if self.items.is_empty() {
            None
        } else {
            Some(self.items.remove(0))
        }
    }
}

fn main() {
    let mut data = MyContainer {
        items: vec![1, 2, 3]
    };

    for item in data {
        println!("Processed item: {:?}", item);
    }
}
